    ConvTransposed3dAsymmetricInputAsymmetricKernelCustomTilingData tiling;

    // Input shapes:
    // x: [N, Cin, Di, Hi, Wi]
    // weight: [Cin, Cout, Kd, Kh, Kw]
    const gert::Shape *xShape = context->GetInputShape(0);
    const gert::Shape *wShape = context->GetInputShape(1);

    const uint64_t n   = static_cast<uint64_t>(xShape->GetDim(0));
    const uint64_t cin = static_cast<uint64_t>(xShape->GetDim(1));
    const uint64_t di  = static_cast<uint64_t>(xShape->GetDim(2));
    const uint64_t hi  = static_cast<uint64_t>(xShape->GetDim(3));
    const uint64_t wi  = static_cast<uint64_t>(xShape->GetDim(4));

    const uint64_t winCin = static_cast<uint64_t>(wShape->GetDim(0));
    const uint64_t cout   = static_cast<uint64_t>(wShape->GetDim(1));
    const uint64_t kd     = static_cast<uint64_t>(wShape->GetDim(2));
    const uint64_t kh     = static_cast<uint64_t>(wShape->GetDim(3));
    const uint64_t kw     = static_cast<uint64_t>(wShape->GetDim(4));

    // Basic validation
    if (winCin != cin) {
        return ge::GRAPH_FAILED;
    }

    // Only stride=(1,1,1), padding=(0,0,0), dilation=(1,1,1), groups=1 supported in this custom kernel.
    // Compute output size for this configuration:
    const uint64_t dout = di + kd - 1;
    const uint64_t hout = hi + kh - 1;
    const uint64_t wout = wi + kw - 1;

    // Choose a conservative tile on W dimension
    const uint32_t UB_BUDGET_BYTES = 192 * 1024; // per-core
    // We need 3 local buffers of size tileW for a simple pipeline (yLocal, temp1, temp2)
    uint32_t tileW = UB_BUDGET_BYTES / (3u * sizeof(float));
    // Favor long DMA bursts. 128 or 256 is a reasonable choice.
    tileW = AlignDown(tileW, 256u);
    if (tileW == 0) tileW = 256u;
    if (tileW > wout) {
        tileW = static_cast<uint32_t>(wout);
        tileW = AlignDown(tileW, 64u);
        if (tileW == 0) tileW = static_cast<uint32_t>(wout);
    }

    // Block strategy: distribute by (n, cout, dout)
    uint64_t workItems = n * cout * dout;
    uint32_t blockDim = static_cast<uint32_t>(workItems);
    if (blockDim == 0) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u; // keep within a safe range for 910B

    context->SetBlockDim(blockDim);

    tiling.set_n(static_cast<uint32_t>(n));
    tiling.set_cin(static_cast<uint32_t>(cin));
    tiling.set_cout(static_cast<uint32_t>(cout));
    tiling.set_din(static_cast<uint32_t>(di));
    tiling.set_hin(static_cast<uint32_t>(hi));
    tiling.set_win(static_cast<uint32_t>(wi));
    tiling.set_kd(static_cast<uint32_t>(kd));
    tiling.set_kh(static_cast<uint32_t>(kh));
    tiling.set_kw(static_cast<uint32_t>(kw));
