at::Tensor conv_transposed_3d_asymmetric_input_asymmetric_kernel_custom_impl_npu(const at::Tensor& x,
                                                                                const at::Tensor& weight) {
    // Output shape: [N, Cout, Di+Kd-1, Hi+Kh-1, Wi+Kw-1]
    TORCH_CHECK(x.dim() == 5, \"x must be 5D NCDHW\");
    TORCH_CHECK(weight.dim() == 5, \"weight must be 5D [Cin, Cout, kD, kH, kW]\");
    TORCH_CHECK(x.size(1) == weight.size(0), \"Cin mismatch between x and weight\");
    auto N  = x.size(0);
    auto Cin = x.size(1);
    auto Di = x.size(2);
    auto Hi = x.size(3);
    auto Wi = x.size(4);
    auto Cout = weight.size(1);
    auto Kd = weight.size(2);
    auto Kh = weight.size(3);
    auto Kw = weight.size(4);
    auto Dout = Di + Kd - 1;
    auto Hout = Hi + Kh - 1;
    auto Wout = Wi + Kw - 1;

    at::Tensor y = at::empty({N, Cout, Dout, Hout, Wout}, x.options());
    EXEC_NPU_CMD(aclnnConvTransposed3dAsymmetricInputAsymmetricKernelCustom, x, weight, y);
    return y;
}

